#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
const int mxn=1e5+9;
vector<PII> g[mxn];
int ds[mxn];
struct nd
{
    int u,d;
    bool operator < (const nd &rhs) const
    {
        return d>rhs.d;
    }
};
priority_queue<nd> q;
bitset<mxn> vs,fl;
int n,m,k;
int dij(int st)
{
    wh(!q.empty())q.pop();
    vs.reset();
    cli(ds);
    q.push((nd){st,0});ds[st]=0;
    wh(!q.empty())
    {
        nd fi=q.top();q.pop();
        int u=fi.u;if(fl[u]&&u!=st)return ds[u];
        if(!vs[u])
        {
            vs[u]=1;
            FOI(e,g[u])
            {
                int v=e.fst,w=e.snd;
                if(ds[v]>ds[u]+w)
                {
                    ds[v]=ds[u]+w;
                    q.push((nd){v,ds[v]});
                }
            }
        }
    }
    return llinf;
}
signed main(void)
{
    int T=read();
    wh(T--)
    {
        FOR(i,1,n)g[i].clear();
        fl.reset();
        n=read(),m=read(),k=read();
        FOR(i,1,m)
        {
            int u=read(),v=read(),w=read();
            g[u].pb(mk(v,w));
        }
        FOR(i,1,k)
        {
            int u=read();
            fl[u]=1;
        }
        int ans=llinf;
        FOR(i,1,n)
        {
            if(fl[i])ans=min(dij(i),ans);
        }
        write(ans);puts("");
    }
    return 0;
}
